// Aggregate results from all sources and rank by confidence
const gutenberg = $input.getByIndex(0)?.json?.results || [];
const openlibrary = $input.getByIndex(1)?.json?.docs || [];
const archive = $input.getByIndex(2)?.json?.response?.docs || [];

const query = $json.item.search_query.toLowerCase();

// Score and rank candidates
const candidates = [
  ...gutenberg.map(book => ({
    title: book.title,
    author: book.authors?.[0]?.name || 'Unknown',
    source: 'gutenberg',
    source_url: book.cover_image,
    formats: book.formats,
    confidence: query.split(' ').filter(q => book.title.toLowerCase().includes(q)).length / query.split(' ').length * 0.9
  })),
  ...openlibrary.map(book => ({
    title: book.title,
    author: book.author_name?.[0] || 'Unknown',
    source: 'openlibrary',
    source_url: book.key,
    confidence: query.split(' ').filter(q => book.title.toLowerCase().includes(q)).length / query.split(' ').length * 0.7
  })),
  ...archive.map(book => ({
    title: book.title,
    author: book.creator ? (Array.isArray(book.creator) ? book.creator[0] : book.creator) : 'Unknown',
    source: 'archive',
    source_url: book.identifier,
    confidence: query.split(' ').filter(q => book.title.toLowerCase().includes(q)).length / query.split(' ').length * 0.8
  }))
];

const best = candidates.sort((a, b) => b.confidence - a.confidence)[0];

if (!best || best.confidence < 0.3) {
  return {json: {
    found: false,
    reason: 'low_confidence',
    search_query: query
  }};
}

// Find PDF format
let downloadUrl = null;
if (best.source === 'gutenberg' && best.formats) {
  const pdf = Object.entries(best.formats).find(([key]) => key.includes('pdf'));
  downloadUrl = pdf ? pdf[1] : null;
}

return {json: {
  ...best,
  found: true,
  download_url: downloadUrl,
  acquisition_id: $env.LIBRARIAN_RUN_ID
}};

// Download the file and validate
const filename = ($json.title || 'unknown').replace(/[<>:"|?*]/g, '_') + '_' + ($json.author || 'unknown').replace(/[<>:"|?*]/g, '_');
const category = $json.item.subject_category || 'uncategorized';
const filepath = `/home/lewis/Desktop/Private Library/${category}/${filename}.pdf`;

// Create directory if needed
const fs = require('fs');
const path = require('path');
const dir = path.dirname(filepath);

if (!fs.existsSync(dir)) {
  fs.mkdirSync(dir, { recursive: true });
}

return {json: {
  title: $json.title,
  author: $json.author,
  source: $json.source,
  source_url: $json.source_url,
  download_url: $json.download_url,
  filepath: filepath,
  category: category,
  found: $json.found,
  confidence: $json.confidence
}};

// Validate downloaded file
const fs = require('fs');
const filepath = $json.filepath;

try {
  // Check if file exists and is valid
  const stats = fs.statSync(filepath);

  // Minimum size check (10KB for PDFs)
  if (stats.size < 10000) {
    throw new Error(`File too small: ${stats.size} bytes`);
  }

  // This is where downloaded content would be validated
  // For now, assume successful if size is adequate

  return {json: {
    valid: true,
    file_size: stats.size,
    file_path: filepath,
    title: $json.title,
    author: $json.author,
    source: $json.source,
    confidence: $json.confidence,
    category: $json.category
  }};
} catch(e) {
  return {json: {
    valid: false,
    error: e.message,
    filepath: filepath,
    title: $json.title
  }};
}
